thread_routine(void *arg)
{
	int thread_id = (intptr_t)arg;
	(void)thread_id;  /* Suppress unused warning if we're not using it for debug output */

	Pthread_detach(Pthread_self());

	/* Get global sbuf pointer - need to make it accessible */
	/* For now, we'll store it globally */
	extern sbuf_t *global_sbuf;

	while (1) {
		int connfd = sbuf_remove(global_sbuf);
		struct sockaddr_in client_addr;
		socklen_t client_len = sizeof(client_addr);

		/* Get the peer address for logging */
		if (getpeername(connfd, (struct sockaddr *)&client_addr, &client_len) < 0) {
			close(connfd);
